function Wishlist({wishes,setWishes}){const[inp,setInp]=useState("");const[cat,setCat]=useState("🎁 Cadeau");const[fw,setFw]=useState("Les deux");const cats=["🎁 Cadeau","🍽️ Resto","🎬 Film/Série","📍 Endroit","🎭 Activité Paris","📦 Autre"];const add=()=>{if(!inp.trim())return;setWishes(p=>[...p,{id:uid(),name:inp.trim(),cat,forWho:fw,done:false}]);setInp("");};return(<Anim k="wl"><div><PH title="💝 Wishlist"/><div style={{...cs,display:"flex",flexDirection:"column",gap:6}}><input value={inp} onChange={e=>setInp(e.target.value)} onKeyDown={e=>e.key==="Enter"&&add()} placeholder="Ajouter…" style={is}/><div style={{display:"flex",gap:5}}><select value={cat} onChange={e=>setCat(e.target.value)} style={{...is,flex:1}}>{cats.map(c=><option key={c} value={c}>{c}</option>)}</select><select value={fw} onChange={e=>setFw(e.target.value)} style={{...is,flex:1}}><option>Les deux</option>{U.map(u=><option key={u}>Pour {u}</option>)}</select></div><button onClick={add} style={{...bp,width:"100%"}}>Ajouter</button></div>{cats.map(c=>{const l=wishes.filter(w=>w.cat===c&&!w.done);if(!l.length)return null;return(<div key={c}><p style={{fontSize:12,color:T.ac,margin:"12px 0 5px"}}>{c}</p>{l.map(w=>(<div key={w.id} style={{...cs,display:"flex",alignItems:"center",gap:8,padding:"10px 14px",marginBottom:3}}><button onClick={()=>setWishes(p=>p.map(x=>x.id===w.id?{...x,done:true}:x))} style={{width:20,height:20,borderRadius:6,border:`2px solid ${T.cb}`,background:"none",cursor:"pointer",flexShrink:0}}/><div style={{flex:1}}><p style={{fontSize:14,color:T.t,margin:0}}>{w.name}</p><p style={{fontSize:10,color:T.t3,margin:0}}>{w.forWho}</p></div><button onClick={()=>setWishes(p=>p.filter(x=>x.id!==w.id))} style={{background:"none",border:"none",color:T.t3,cursor:"pointer"}}>✕</button></div>))}</div>);})}
</div></Anim>);}
function Jar({jarItems,setJarItems}){const[inp,setInp]=useState("");const[pick,setPick]=useState(null);const[spin,setSpin]=useState(false);const add=()=>{if(!inp.trim())return;setJarItems(p=>[...p,inp.trim()]);setInp("");};const rand=()=>{if(!jarItems.length)return;setSpin(true);setPick(null);setTimeout(()=>{setPick(jarItems[Math.floor(Math.random()*jarItems.length)]);setSpin(false);},1000);};return(<Anim k="jar"><div><PH title="🎲 On fait quoi ?"/><div style={{...cs,textAlign:"center",background:`linear-gradient(135deg,${T.rg},${T.bg2})`,minHeight:100,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}>{spin&&<p style={{fontSize:30,margin:0,animation:"spin 0.3s linear infinite"}}>🎰</p>}{!spin&&!pick&&<p style={{fontSize:14,color:T.t2,margin:0}}>Appuie !</p>}{!spin&&pick&&<><p style={{fontSize:24,margin:"0 0 4px"}}>🎉</p><p style={{fontSize:18,fontWeight:700,color:T.t,margin:0}}>{pick}</p></>}</div><button onClick={rand} style={{...bp,width:"100%",marginBottom:10}}>🎲 Piocher</button><div style={{...cs,display:"flex",gap:5}}><input value={inp} onChange={e=>setInp(e.target.value)} onKeyDown={e=>e.key==="Enter"&&add()} placeholder="Idée…" style={{...is,flex:1,marginBottom:0}}/><button onClick={add} style={{...bp,padding:"13px 14px"}}>+</button></div>{jarItems.map((item,i)=>(<div key={i} style={{...cs,display:"flex",alignItems:"center",gap:6,padding:"8px 14px",marginBottom:3}}><span style={{color:T.ac}}>✦</span><span style={{flex:1,fontSize:13,color:T.t}}>{item}</span><button onClick={()=>setJarItems(p=>p.filter((_,j)=>j!==i))} style={{background:"none",border:"none",color:T.t3,cursor:"pointer"}}>✕</button></div>))}</div></Anim>);}
function Notes({notes,setNotes,user}){const[inp,setInp]=useState("");const add=()=>{if(!inp.trim())return;setNotes(p=>[{id:uid(),text:inp.trim(),by:user,date:new Date().toISOString()},...p]);setInp("");};return(<Anim k="notes"><div><PH title="📝 Notes"/><div style={{...cs,display:"flex",flexDirection:"column",gap:5}}><textarea value={inp} onChange={e=>setInp(e.target.value)} placeholder="Un mot…" rows={2} style={{...is,resize:"vertical"}}/><button onClick={add} style={{...bp,width:"100%"}}>Poster</button></div>{notes.map(n=>(<div key={n.id} style={{...cs,padding:"10px 14px",marginBottom:5,borderLeft:`4px solid ${n.by===U[0]?T.red:T.blue}`}}><p style={{fontSize:14,color:T.t,margin:0,whiteSpace:"pre-wrap"}}>{n.text}</p><div style={{display:"flex",justifyContent:"space-between",marginTop:5}}><p style={{fontSize:10,color:T.t3,margin:0}}>{n.by} · {new Date(n.date).toLocaleDateString("fr-FR",{day:"numeric",month:"short"})}</p><button onClick={()=>setNotes(p=>p.filter(x=>x.id!==n.id))} style={{background:"none",border:"none",color:T.t3,cursor:"pointer",fontSize:11}}>✕</button></div></div>))}</div></Anim>);}
function Photos({photos,setPhotos}){const[cap,setCap]=useState("");const[dt,setDt]=useState(new Date().toISOString().slice(0,10));const[em,setEm]=useState("📸");const add=()=>{if(!cap.trim())return;setPhotos(p=>[{id:uid(),caption:cap.trim(),date:dt,emoji:em},...p]);setCap("");};return(<Anim k="ph"><div><PH title="📸 Souvenirs"/><div style={{...cs,display:"flex",flexDirection:"column",gap:5}}><div style={{display:"flex",gap:5}}><input value={em} onChange={e=>setEm(e.target.value)} style={{...is,width:44,textAlign:"center",fontSize:18}}/><input value={cap} onChange={e=>setCap(e.target.value)} placeholder="Souvenir…" style={{...is,flex:1}}/></div><div style={{display:"flex",gap:5}}><input type="date" value={dt} onChange={e=>setDt(e.target.value)} style={{...is,flex:1}}/><button onClick={add} style={{...bp,flex:1}}>+</button></div></div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6}}>{photos.map(p=>(<div key={p.id} style={{...cs,textAlign:"center",padding:"14px 10px",background:`linear-gradient(135deg,${T.rg},${T.bg2})`,position:"relative"}}><span style={{fontSize:30}}>{p.emoji}</span><p style={{fontSize:13,fontWeight:600,color:T.t,margin:"5px 0 2px"}}>{p.caption}</p><p style={{fontSize:10,color:T.t3,margin:0}}>{new Date(p.date).toLocaleDateString("fr-FR",{day:"numeric",month:"long"})}</p><button onClick={()=>setPhotos(pp=>pp.filter(x=>x.id!==p.id))} style={{position:"absolute",top:4,right:6,background:"none",border:"none",color:T.t3,cursor:"pointer",fontSize:11}}>✕</button></div>))}</div></div></Anim>);}
function Countdowns({countdowns,setCountdowns}){const[sa,setSa]=useState(false);const[form,setForm]=useState({name:"",emoji:"🎉",date:""});const add=()=>{if(!form.name.trim()||!form.date)return;setCountdowns(p=>[...p,{id:uid(),...form}].sort((a,b)=>new Date(a.date)-new Date(b.date)));setForm({name:"",emoji:"🎉",date:""});setSa(false);};const up=countdowns.filter(c=>new Date(c.date)>=new Date());return(<Anim k="cd"><div><PH title="⏳ Compte à rebours"/>{!sa&&<button onClick={()=>setSa(true)} style={{...bp,width:"100%",marginBottom:10}}>+ Ajouter</button>}{sa&&<div style={{...cs,display:"flex",flexDirection:"column",gap:6,marginBottom:10}}><div style={{display:"flex",gap:6}}><input value={form.emoji} onChange={e=>setForm(p=>({...p,emoji:e.target.value}))} style={{...is,width:48,textAlign:"center",fontSize:18}}/><input value={form.name} onChange={e=>setForm(p=>({...p,name:e.target.value}))} placeholder="Événement" style={{...is,flex:1}}/></div><input type="date" value={form.date} onChange={e=>setForm(p=>({...p,date:e.target.value}))} style={is}/><div style={{display:"flex",gap:6}}><button onClick={()=>setSa(false)} style={{...bg3,flex:1}}>Annuler</button><button onClick={add} style={{...bp,flex:1}}>OK</button></div></div>}{up.map(c=>{const dl=Math.max(0,Math.ceil((new Date(c.date)-new Date())/864e5));return(<div key={c.id} style={{...cs,display:"flex",alignItems:"center",gap:12,padding:"14px 16px"}}><span style={{fontSize:28}}>{c.emoji}</span><div style={{flex:1}}><p style={{fontSize:16,fontWeight:600,color:T.t,margin:0}}>{c.name}</p><p style={{fontSize:12,color:T.t3,margin:0}}>{new Date(c.date).toLocaleDateString("fr-FR",{weekday:"long",day:"numeric",month:"long"})}</p></div><div style={{textAlign:"center"}}><p style={{fontSize:26,fontWeight:700,color:T.pk,margin:0}}>{dl}</p><p style={{fontSize:10,color:T.t3,margin:0}}>j</p></div><button onClick={()=>setCountdowns(p=>p.filter(x=>x.id!==c.id))} style={{background:"none",border:"none",color:T.t3,cursor:"pointer"}}>✕</button></div>);})}</div></Anim>);}
function MoreMenu({onNav}){const items=[{k:"wishlist",i:"💝",l:"Wishlist",d:"Cadeaux, restos, activités"},{k:"jar",i:"🎲",l:"On fait quoi ?",d:"Piocher une idée"},{k:"countdowns",i:"⏳",l:"Compte à rebours",d:"Anniversaires"},{k:"notes",i:"📝",l:"Notes",d:"Pense-bête"},{k:"photos",i:"📸",l:"Souvenirs",d:"Moments"}];return(<Anim k="more"><div><PH title="✨ Plus"/>{items.map(x=>(<button key={x.k} onClick={()=>onNav(x.k)} style={{...cs,display:"flex",alignItems:"center",gap:10,cursor:"pointer",width:"100%",padding:"14px 16px"}}><span style={{fontSize:24}}>{x.i}</span><div style={{flex:1,textAlign:"left"}}><p style={{fontSize:15,fontWeight:600,color:T.t,margin:0}}>{x.l}</p><p style={{fontSize:12,color:T.t3,margin:0}}>{x.d}</p></div><span style={{color:T.t3}}>→</span></button>))}</div></Anim>);}
